// =====================================================================
// EDITA ESTE VALOR ANTES DE EJECUTAR:
const HUB_SELECCIONADO = 'Salud';
// Opciones válidas: 'Salud', 'Alimentación', 'Razas', 'Comportamiento'
// =====================================================================

// Títulos en SENTENCE CASE: solo primera letra mayúscula + nombres propios (Bigotes Caninos = marca)
const PILARES = {
  'Salud': {
    slug: 'guia-salud-canina',
    titulo: 'Guía completa de salud canina: todo lo que una familia perruna necesita saber',
    seo_title: 'Salud canina: guía completa para familias perrunas | Bigotes Caninos',
    descripcion_meta: 'Guía maestra sobre salud preventiva, enfermedades comunes, vacunas y cuidados veterinarios para perros. Recursos verificados por veterinarios.',
    descripcion_corta: 'prevención, diagnóstico, vacunas y bienestar veterinario',
    keyword_focus: 'salud canina',
    descripcion_imagen: 'Healthy adult dog sitting alert and well-groomed in a bright, clean veterinary setting with soft natural light, 85mm portrait lens, sharp focus on coat texture, warm medical environment'
  },
  'Alimentación': {
    slug: 'guia-alimentacion-perros',
    titulo: 'Alimentación canina: la guía definitiva para tu perro',
    seo_title: 'Alimentación de perros: guía definitiva 2026 | Bigotes Caninos',
    descripcion_meta: 'Todo sobre alimentación canina: dietas, marcas, suplementos, qué pueden y no pueden comer los perros. Recomendaciones veterinarias.',
    descripcion_corta: 'nutrición, dietas, marcas y qué pueden o no comer los perros',
    keyword_focus: 'alimentación canina',
    descripcion_imagen: 'Healthy adult dog eating from a clean ceramic bowl with high-quality dog food, kitchen counter setting, warm natural light, 85mm portrait lens, sharp focus on dog fur and food texture'
  },
  'Razas': {
    slug: 'guia-razas-perros',
    titulo: 'Razas de perros: la guía completa para elegir tu compañero',
    seo_title: 'Razas de perros: guía completa con características | Bigotes Caninos',
    descripcion_meta: 'Características, temperamento y cuidados de las razas de perros más populares. Comparativa para elegir tu compañero ideal.',
    descripcion_corta: 'características, temperamento y cuidados de las razas más populares',
    keyword_focus: 'razas de perros',
    descripcion_imagen: 'Three different dog breeds (Golden Retriever, Pastor Alemán, Border Collie) sitting together in a bright living room, showing breed diversity, 85mm portrait lens, sharp focus on coat textures, warm golden hour light'
  },
  'Comportamiento': {
    slug: 'guia-comportamiento-canino',
    titulo: 'El comportamiento canino explicado: guía para entender a tu perro',
    seo_title: 'Comportamiento de perros: guía para entender a tu canino | Bigotes Caninos',
    descripcion_meta: 'Comportamiento, curiosidades, juegos y cuidados generales de los perros. Aprende a entender a tu compañero canino.',
    descripcion_corta: 'comportamiento, curiosidades, juegos y cuidados generales',
    keyword_focus: 'comportamiento canino',
    descripcion_imagen: 'Curious dog exploring a cozy home environment with toys and dog bed, alert posture, sharp focus on whiskers and eyes, warm indoor natural light, 85mm portrait lens'
  }
};

const config = PILARES[HUB_SELECCIONADO];
if (!config) throw new Error('Hub inválido: ' + HUB_SELECCIONADO + '. Opciones: Salud, Alimentación, Razas, Comportamiento');

return [{ json: { hub: HUB_SELECCIONADO, ...config } }];

const sheetResp = $input.first().json;
const values = sheetResp.values || [];
const cfg = $('Definir Hub').first().json;

const rows = values.slice(1);
const clusters = [];
for (const row of rows) {
  const keyword = (row[0] || '').trim();
  const estado = (row[1] || '').trim();
  const urlPost = (row[7] || '').trim();
  const hubCol = (row[17] || '').trim();
  if (hubCol === cfg.hub && keyword) {
    clusters.push({ keyword, estado, urlPost });
  }
}

const publicados = clusters.filter(c => c.estado === 'Publicado');
const aprobados = clusters.filter(c => c.estado === 'Aprobado' || c.estado === 'Pendiente');

return [{ json: { ...cfg, clusters_total: clusters.length, clusters_publicados: publicados.length, clusters_pendientes: aprobados.length, lista_publicados: publicados, lista_pendientes: aprobados } }];

const gptResp = $input.first().json;
const cfg = $('Filtrar Clusters del Hub').first().json;

const raw = gptResp.choices && gptResp.choices[0] && gptResp.choices[0].message ? gptResp.choices[0].message.content : '{}';
let data;
try { data = JSON.parse(raw); } catch(e) { throw new Error('Pilar parse error: ' + raw.substring(0, 300)); }

function strip4Byte(s) { return (s || '').replace(/[\u{10000}-\u{10FFFF}]/gu, ''); }
function scrubAIWatermarks(s) {
  if (!s) return s;
  let r = s.replace(/[​-‏⁠­ ﻿]/g, '');
  r = r.replace(/\p{Cf}/gu, '');
  r = r.replace(/(\w+)\s—\s([A-ZÁÉÍÓÚÑ])/g, '$1. $2');
  r = r.replace(/(\w+)\s—\s(\w)/g, '$1, $2');
  r = r.replace(/  +/g, ' ').replace(/\n{3,}/g, '\n\n');
  return r;
}
function clean(s) { return scrubAIWatermarks(strip4Byte(s || '')); }
function esc(s) { return (s || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;'); }

// Convertir TitleCase a sentence case en headings (preserva nombres propios comunes)
const PROPER_NOUNS = new Set(['colombia','bogotá','medellín','cali','barranquilla','cartagena','méxico','españa','argentina','chile','perú','wsava','avma','msd','aafp','pubmed','royal canin','hill','bigotes caninos']);
function headingsToSentenceCase(html) {
  return html.replace(/<(h[2-6])>([\s\S]*?)<\/\1>/g, (m, tag, content) => {
    // Decode entities básicas
    let text = content.replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&quot;/g, '"');
    // Si el heading tiene más de 50% palabras en TitleCase, normalizar
    const words = text.split(/\s+/).filter(w => w.length > 0);
    const titleCount = words.filter(w => /^[A-ZÁÉÍÓÚÑ][a-záéíóúñ]+$/.test(w)).length;
    if (titleCount < words.length * 0.5) return m; // ya está OK
    // Normalizar: lowercase + cap primera letra alfanumérica + preservar nombres propios
    let lower = text.toLowerCase();
    // Capitalizar la primera letra alfabética
    lower = lower.replace(/^([¿\s]*)([a-záéíóúñ])/, (mm, pre, c) => pre + c.toUpperCase());
    // Restaurar nombres propios
    for (const noun of PROPER_NOUNS) {
      const re = new RegExp('\\b' + noun.replace(/[.*+?^${}()|[\]\\]/g, '\\$&') + '\\b', 'gi');
      lower = lower.replace(re, noun.charAt(0).toUpperCase() + noun.slice(1));
    }
    return '<' + tag + '>' + lower + '</' + tag + '>';
  });
}

const respuestaDirecta = clean(data.respuesta_directa);
if (!respuestaDirecta) throw new Error('respuesta_directa vacía');

const keyTakeaways = (data.key_takeaways || []).map(clean).filter(t => t);
const introHtml = clean(data.intro_html);
let seccionesHtml = clean(data.secciones_html);
seccionesHtml = headingsToSentenceCase(seccionesHtml);
const tablaHtml = strip4Byte(data.tabla_html || '');
if (!tablaHtml || (!tablaHtml.includes('<table') && !tablaHtml.includes('<dl'))) throw new Error('Tabla obligatoria ausente');

const faqItems = (data.faq_items || []).map(f => ({ q: clean(f.q), a: clean(f.a) })).filter(f => f.q && f.a);
if (faqItems.length < 5) throw new Error('FAQ insuficiente: ' + faqItems.length + ' items, mínimo 5');

const fuentes = (data.fuentes_consultadas || []).filter(f => f.nombre && f.url);
if (fuentes.length < 3) throw new Error('Fuentes insuficientes: ' + fuentes.length + ', mínimo 3');

const entities = (data.entities || []).filter(e => e.nombre && e.wikipedia_url);
const basePrompt = data.prompt_imagen || cfg.descripcion_imagen;
const promptImagen = basePrompt + ', 16:9 horizontal cinematic widescreen aspect ratio, professional editorial photography, sharp focus, high quality';

const ktHtml = '<blockquote class="key-takeaways"><h3>Lo importante en pocas palabras</h3><ul>' + keyTakeaways.map(t => '<li>' + t + '</li>').join('') + '</ul></blockquote>';

const faqHtml = '<h2>Preguntas frecuentes</h2>' + faqItems.map(f => '<h3>' + f.q + '</h3><p>' + f.a + '</p>').join('');

const fuentesHtml = '<section class="fuentes-consultadas"><h3>Fuentes consultadas</h3><ul>' + fuentes.map(f => '<li><a href="' + esc(f.url) + '" rel="nofollow noopener" target="_blank">' + esc(f.nombre) + '</a> — ' + esc(f.descripcion || '') + '</li>').join('') + '</ul></section>';

const faqJsonLD = '<script type="application/ld+json">' + JSON.stringify({
  '@context': 'https://schema.org',
  '@type': 'FAQPage',
  'mainEntity': faqItems.map(f => ({ '@type': 'Question', 'name': f.q, 'acceptedAnswer': { '@type': 'Answer', 'text': f.a } }))
}) + '</script>';

const pilarUrl = 'https://bigotescaninos.com/' + cfg.slug + '/';
const collJsonLD = '<script type="application/ld+json">' + JSON.stringify({
  '@context': 'https://schema.org',
  '@type': 'CollectionPage',
  'name': cfg.titulo,
  'description': cfg.descripcion_meta,
  'url': pilarUrl,
  'inLanguage': 'es-ES',
  'speakable': { '@type': 'SpeakableSpecification', 'cssSelector': ['.respuesta-directa', '.key-takeaways'] },
  'mentions': entities.map(e => ({ '@type': 'Thing', 'name': e.nombre, 'sameAs': e.wikipedia_url }))
}) + '</script>';

const bodyHtml = '<p class="respuesta-directa">' + respuestaDirecta + '</p>' +
  introHtml +
  ktHtml +
  seccionesHtml +
  tablaHtml +
  faqHtml +
  fuentesHtml +
  faqJsonLD +
  collJsonLD;

const wpBody = {
  title: cfg.titulo,
  slug: cfg.slug,
  content: bodyHtml,
  status: 'publish',
  excerpt: cfg.descripcion_meta,
  meta: {
    _yoast_wpseo_title: cfg.seo_title,
    _yoast_wpseo_metadesc: cfg.descripcion_meta,
    _yoast_wpseo_focuskw: cfg.keyword_focus
  }
};

const geminiBody = {
  contents: [{ parts: [{ text: promptImagen }] }],
  generationConfig: { responseModalities: ['IMAGE'] }
};

const wordCount = bodyHtml.replace(/<[^>]+>/g, ' ').split(/\s+/).filter(w => w.length > 0).length;

return [{ json: { wp_body_json: JSON.stringify(wpBody), gemini_body_json: JSON.stringify(geminiBody), prompt_imagen: promptImagen, hub: cfg.hub, slug: cfg.slug, titulo: cfg.titulo, keyword_focus: cfg.keyword_focus, word_count: wordCount, faq_count: faqItems.length, fuentes_count: fuentes.length, entities_count: entities.length, internal_links: (bodyHtml.match(/href="https:\/\/bigotescaninos\.com/g) || []).length } }];

const resp = $input.first().json;
const cfg = $('Parsear y Construir HTML').first().json;

const parts = resp.candidates && resp.candidates[0] && resp.candidates[0].content && resp.candidates[0].content.parts ? resp.candidates[0].content.parts : [];
const imgPart = parts.find(p => p.inlineData && p.inlineData.data);

if (imgPart) {
  const base64 = imgPart.inlineData.data;
  const mime = imgPart.inlineData.mimeType || 'image/png';
  const buffer = Buffer.from(base64, 'base64');
  const filename = 'pilar-img-' + cfg.slug + '.webp';
  return [{
    json: { ...cfg, image_available: true, image_mime: mime, image_filename: filename },
    binary: { data: { data: buffer.toString('base64'), mimeType: mime, fileName: filename, fileExtension: 'webp' } }
  }];
} else {
  console.log('Gemini falló tras 3 intentos. Publicando pilar SIN imagen destacada.');
  return [{ json: { ...cfg, image_available: false } }];
}

const cfg = $('Parsear y Construir HTML').first().json;
const wpBody = JSON.parse(cfg.wp_body_json);

const input = $input.first().json;
let mediaId = null;
let imageAvailable = false;

if (input.id && typeof input.id === 'number') {
  mediaId = input.id;
  imageAvailable = true;
  wpBody.featured_media = mediaId;
} else if (input.image_available === false) {
  imageAvailable = false;
}

return [{ json: { ...cfg, wp_body_final_json: JSON.stringify(wpBody), media_id: mediaId, image_available: imageAvailable } }];

